module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);
reg [2:0] state;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= 3'b000;
        data_out <= 1'b0;
    end 
    else begin
        case(state)
            3'b000: begin
                if(data_in == 1'b1) state <= 3'b001; else state <= 3'b000;
            end

            3'b001: begin
                if(data_in == 1'b0) state <= 3'b010; else state <= 3'b001;
            end

            3'b010: begin
                if(data_in == 1'b1) state <= 3'b011; else state <= 3'b000;
            end

            3'b011: begin
                if(data_in == 1'b0) state <= 3'b100; else state <= 3'b001;
            end

            3'b100: begin
                if(data_in == 1'b1) state <= 3'b010; else state <= 3'b000;
            end

            default: begin
                state <= 3'b000;
            end
        endcase

        if((state == 3'b011) && (data_in == 1'b0))
            data_out <= 1'b1;
            data_out <= 1'b0;
    end
end
endmodule
